insert into "supabase_migrations"."schema_migrations" ("created_by", "idempotency_key", "name", "rollback", "statements", "version") values ('luanscps@gmail.com', NULL, 'fix_rls_policies_new_tables_and_search_path', NULL, E'{"-- =====================================================\\n-- MIGRATION: Corrigir RLS nas 5 tabelas novas + search_path das funções\\n-- Data: 2026-04-22\\n-- =====================================================\\n\\n-- ===== prize_distribution =====\\nCREATE POLICY \\"prize_dist_select_all\\" ON public.prize_distribution FOR SELECT USING (true);\\nCREATE POLICY \\"prize_dist_insert_admin\\" ON public.prize_distribution FOR INSERT WITH CHECK (is_admin(auth.uid()));\\nCREATE POLICY \\"prize_dist_update_admin\\" ON public.prize_distribution FOR UPDATE USING (is_admin(auth.uid()));\\nCREATE POLICY \\"prize_dist_delete_admin\\" ON public.prize_distribution FOR DELETE USING (is_admin(auth.uid()));\\n\\n-- ===== seedings =====\\nCREATE POLICY \\"seedings_select_all\\" ON public.seedings FOR SELECT USING (true);\\nCREATE POLICY \\"seedings_insert_admin\\" ON public.seedings FOR INSERT WITH CHECK (is_admin(auth.uid()));\\nCREATE POLICY \\"seedings_update_admin\\" ON public.seedings FOR UPDATE USING (is_admin(auth.uid()));\\nCREATE POLICY \\"seedings_delete_admin\\" ON public.seedings FOR DELETE USING (is_admin(auth.uid()));\\n\\n-- ===== team_invites =====\\nCREATE POLICY \\"team_invites_select_owner_or_admin\\" ON public.team_invites FOR SELECT\\n  USING (\\n    is_admin(auth.uid()) OR\\n    auth.uid() IN (SELECT owner_id FROM public.teams WHERE id = team_id)\\n  );\\nCREATE POLICY \\"team_invites_insert_owner_or_admin\\" ON public.team_invites FOR INSERT\\n  WITH CHECK (\\n    is_admin(auth.uid()) OR\\n    auth.uid() IN (SELECT owner_id FROM public.teams WHERE id = team_id)\\n  );\\nCREATE POLICY \\"team_invites_update_owner_or_admin\\" ON public.team_invites FOR UPDATE\\n  USING (\\n    is_admin(auth.uid()) OR\\n    auth.uid() IN (SELECT owner_id FROM public.teams WHERE id = team_id)\\n  );\\nCREATE POLICY \\"team_invites_delete_owner_or_admin\\" ON public.team_invites FOR DELETE\\n  USING (\\n    is_admin(auth.uid()) OR\\n    auth.uid() IN (SELECT owner_id FROM public.teams WHERE id = team_id)\\n  );\\n\\n-- ===== disputes =====\\nCREATE POLICY \\"disputes_select_auth\\" ON public.disputes FOR SELECT\\n  USING (auth.role() = ''authenticated'');\\nCREATE POLICY \\"disputes_insert_auth\\" ON public.disputes FOR INSERT\\n  WITH CHECK (auth.uid() = reported_by);\\nCREATE POLICY \\"disputes_update_admin\\" ON public.disputes FOR UPDATE\\n  USING (is_admin(auth.uid()));\\nCREATE POLICY \\"disputes_delete_admin\\" ON public.disputes FOR DELETE\\n  USING (is_admin(auth.uid()));\\n\\n-- ===== tournament_rules =====\\nCREATE POLICY \\"rules_select_all\\" ON public.tournament_rules FOR SELECT USING (true);\\nCREATE POLICY \\"rules_insert_admin\\" ON public.tournament_rules FOR INSERT WITH CHECK (is_admin(auth.uid()));\\nCREATE POLICY \\"rules_update_admin\\" ON public.tournament_rules FOR UPDATE USING (is_admin(auth.uid()));\\nCREATE POLICY \\"rules_delete_admin\\" ON public.tournament_rules FOR DELETE USING (is_admin(auth.uid()));\\n\\n-- =====================================================\\n-- Corrigir search_path mutável nas funções (vulnerabilidade schema hijacking)\\n-- =====================================================\\nALTER FUNCTION public.handle_new_user() SET search_path = public, extensions;\\nALTER FUNCTION public.is_admin(uuid) SET search_path = public;\\nALTER FUNCTION public.set_updated_at() SET search_path = public;\\nALTER FUNCTION public.audit_matches_changes() SET search_path = public;\\nALTER FUNCTION public.log_admin_action(p_action text, p_table_name text, p_record_id text, p_old_data jsonb, p_new_data jsonb) SET search_path = public;\\n"}', '20260422222656');
insert into "supabase_migrations"."schema_migrations" ("created_by", "idempotency_key", "name", "rollback", "statements", "version") values ('luanscps@gmail.com', NULL, 'fix_security_definer_views', NULL, E'{"-- =====================================================\\n-- MIGRATION: Corrigir SECURITY DEFINER nas views\\n-- Recriar com a definição original + security_invoker\\n-- Data: 2026-04-22\\n-- =====================================================\\n\\nDROP VIEW IF EXISTS public.v_player_tournament_kda;\\nDROP VIEW IF EXISTS public.v_stage_standings;\\n\\n-- Recriar v_player_tournament_kda com security_invoker\\nCREATE VIEW public.v_player_tournament_kda\\nWITH (security_invoker = true)\\nAS\\nSELECT\\n  ps.player_id,\\n  p.summoner_name,\\n  m.tournament_id,\\n  count(ps.id) AS games_played,\\n  round(avg(ps.kills), 2) AS avg_kills,\\n  round(avg(ps.deaths), 2) AS avg_deaths,\\n  round(avg(ps.assists), 2) AS avg_assists,\\n  round(\\n    CASE\\n      WHEN (avg(ps.deaths) = 0) THEN (avg(ps.kills) + avg(ps.assists))\\n      ELSE ((avg(ps.kills) + avg(ps.assists)) / avg(ps.deaths))\\n    END, 2) AS kda_ratio,\\n  count(ps.id) FILTER (WHERE ps.is_mvp = true) AS mvp_count\\nFROM player_stats ps\\nJOIN players p ON p.id = ps.player_id\\nJOIN match_games mg ON mg.id = ps.game_id\\nJOIN matches m ON m.id = mg.match_id\\nGROUP BY ps.player_id, p.summoner_name, m.tournament_id;\\n\\n-- Recriar v_stage_standings com security_invoker\\nCREATE VIEW public.v_stage_standings\\nWITH (security_invoker = true)\\nAS\\nSELECT\\n  ts.tournament_id,\\n  ts.id AS stage_id,\\n  ts.name AS stage_name,\\n  t.id AS team_id,\\n  t.name AS team_name,\\n  t.tag,\\n  count(m.id) FILTER (WHERE m.winner_id = t.id) AS wins,\\n  count(m.id) FILTER (WHERE m.winner_id IS NOT NULL AND m.winner_id <> t.id AND (m.team_a_id = t.id OR m.team_b_id = t.id)) AS losses,\\n  (count(m.id) FILTER (WHERE m.winner_id = t.id) * 3) AS points\\nFROM tournament_stages ts\\nJOIN matches m ON m.stage_id = ts.id\\nJOIN teams t ON (t.id = m.team_a_id OR t.id = m.team_b_id)\\nWHERE m.status = ''FINISHED''::match_status\\nGROUP BY ts.tournament_id, ts.id, ts.name, t.id, t.name, t.tag;\\n"}', '20260422222745');
insert into "supabase_migrations"."schema_migrations" ("created_by", "idempotency_key", "name", "rollback", "statements", "version") values ('luanscps@gmail.com', NULL, 'fix_rls_audit_log_notifications_and_add_slug_tournaments', NULL, E'{"-- =====================================================\\n-- MIGRATION: Corrigir policies permissivas + adicionar slug em tournaments\\n-- Data: 2026-04-22\\n-- =====================================================\\n\\n-- Corrigir audit_log INSERT: restringir ao service_role e funções internas\\nDROP POLICY IF EXISTS \\"System can insert audit log\\" ON public.audit_log;\\nCREATE POLICY \\"audit_log_insert_service_role\\" ON public.audit_log\\n  FOR INSERT\\n  WITH CHECK (auth.role() = ''service_role'');\\n\\n-- Corrigir notifications INSERT: restringir ao service_role\\nDROP POLICY IF EXISTS \\"notifications_insert_svc\\" ON public.notifications;\\nCREATE POLICY \\"notifications_insert_service_role\\" ON public.notifications\\n  FOR INSERT\\n  WITH CHECK (auth.role() = ''service_role'');\\n\\n-- Adicionar coluna slug em tournaments para URLs públicas amigáveis\\nALTER TABLE public.tournaments\\n  ADD COLUMN IF NOT EXISTS slug text UNIQUE;\\n\\n-- Index para busca rápida por slug\\nCREATE INDEX IF NOT EXISTS tournaments_slug_idx ON public.tournaments(slug);\\n\\n-- Função para gerar slug automático a partir do nome\\nCREATE OR REPLACE FUNCTION public.generate_tournament_slug()\\nRETURNS TRIGGER\\nLANGUAGE plpgsql\\nSET search_path = public\\nAS $$\\nDECLARE\\n  base_slug text;\\n  final_slug text;\\n  counter integer := 0;\\nBEGIN\\n  IF NEW.slug IS NULL OR NEW.slug = '''' THEN\\n    base_slug := lower(regexp_replace(unaccent(NEW.name), ''[^a-z0-9]+'', ''-'', ''g''));\\n    base_slug := trim(both ''-'' from base_slug);\\n    final_slug := base_slug;\\n    WHILE EXISTS (SELECT 1 FROM public.tournaments WHERE slug = final_slug AND id != NEW.id) LOOP\\n      counter := counter + 1;\\n      final_slug := base_slug || ''-'' || counter;\\n    END LOOP;\\n    NEW.slug := final_slug;\\n  END IF;\\n  RETURN NEW;\\nEND;\\n$$;\\n\\nDROP TRIGGER IF EXISTS set_tournament_slug ON public.tournaments;\\nCREATE TRIGGER set_tournament_slug\\n  BEFORE INSERT OR UPDATE ON public.tournaments\\n  FOR EACH ROW EXECUTE FUNCTION public.generate_tournament_slug();\\n\\n-- Adicionar coluna featured para destacar torneios na home\\nALTER TABLE public.tournaments\\n  ADD COLUMN IF NOT EXISTS featured boolean DEFAULT false;\\n\\n-- Adicionar banner_url para imagem de capa do torneio\\nALTER TABLE public.tournaments\\n  ADD COLUMN IF NOT EXISTS banner_url text;\\n\\n-- Adicionar registration_deadline para data limite de inscrições\\nALTER TABLE public.tournaments\\n  ADD COLUMN IF NOT EXISTS registration_deadline timestamptz;\\n"}', '20260422222807');
insert into "supabase_migrations"."schema_migrations" ("created_by", "idempotency_key", "name", "rollback", "statements", "version") values ('luanscps@gmail.com', NULL, 'add_player_leaderboard_view_and_performance_indexes', NULL, E'{"-- =====================================================\\n-- MIGRATION: View de leaderboard global + índices de performance\\n-- Data: 2026-04-22\\n-- =====================================================\\n\\n-- Instalar extensão unaccent no schema extensions (se ainda não existir)\\nCREATE EXTENSION IF NOT EXISTS unaccent WITH SCHEMA extensions;\\n\\n-- View de leaderboard global de jogadores\\nCREATE OR REPLACE VIEW public.v_player_leaderboard\\nWITH (security_invoker = true)\\nAS\\nSELECT\\n  p.id AS player_id,\\n  p.summoner_name,\\n  p.tag_line,\\n  p.tier,\\n  p.rank,\\n  p.lp,\\n  p.profile_icon,\\n  COUNT(DISTINCT t.tournament_id) AS tournaments_played,\\n  SUM(ps.kills) AS total_kills,\\n  SUM(ps.deaths) AS total_deaths,\\n  SUM(ps.assists) AS total_assists,\\n  ROUND(\\n    (SUM(ps.kills)::numeric + SUM(ps.assists)::numeric)\\n    / NULLIF(SUM(ps.deaths)::numeric, 0), 2\\n  ) AS kda_ratio,\\n  COUNT(ps.id) FILTER (WHERE ps.is_mvp = true) AS mvp_count,\\n  COUNT(ps.id) AS total_games\\nFROM public.players p\\nLEFT JOIN public.player_stats ps ON ps.player_id = p.id\\nLEFT JOIN public.teams t ON t.id = p.team_id\\nGROUP BY p.id, p.summoner_name, p.tag_line, p.tier, p.rank, p.lp, p.profile_icon\\nORDER BY kda_ratio DESC NULLS LAST;\\n\\n-- Índices de performance para queries frequentes\\nCREATE INDEX IF NOT EXISTS idx_player_stats_player_id ON public.player_stats(player_id);\\nCREATE INDEX IF NOT EXISTS idx_player_stats_game_id ON public.player_stats(game_id);\\nCREATE INDEX IF NOT EXISTS idx_players_team_id ON public.players(team_id);\\nCREATE INDEX IF NOT EXISTS idx_players_puuid ON public.players(puuid) WHERE puuid IS NOT NULL;\\nCREATE INDEX IF NOT EXISTS idx_matches_tournament_id ON public.matches(tournament_id);\\nCREATE INDEX IF NOT EXISTS idx_matches_stage_id ON public.matches(stage_id) WHERE stage_id IS NOT NULL;\\nCREATE INDEX IF NOT EXISTS idx_matches_status ON public.matches(status);\\nCREATE INDEX IF NOT EXISTS idx_inscricoes_tournament_status ON public.inscricoes(tournament_id, status);\\nCREATE INDEX IF NOT EXISTS idx_notifications_user_unread ON public.notifications(user_id, read) WHERE read = false;\\nCREATE INDEX IF NOT EXISTS idx_audit_log_created_at ON public.audit_log(created_at DESC);\\nCREATE INDEX IF NOT EXISTS idx_audit_log_admin_id ON public.audit_log(admin_id);\\n"}', '20260422222824');
